import { Component, signal } from '@angular/core';
import { AXChartLegendComponent } from '@acorex/charts/chart-legend';
import { AXChartLegendOptions } from '@acorex/charts/chart-legend';
import { AXChartLegendItem } from '@acorex/charts/chart-legend';
import { AXDonutChartComponent } from '@acorex/charts/donut-chart';
import { AXDonutChartData } from '@acorex/charts/donut-chart';
import { AXDonutChartOption } from '@acorex/charts/donut-chart';

@Component({
  template: `
    <div class="showcase-container">
      <h2>Interactive Chart Legend</h2>
      <div class="chart-legend-demo">
        <ax-donut-chart 
          [data]="showcaseData()" 
          [options]="showcaseChartOptions()"
          #chartRef
        />
        <ax-chart-legend 
          [chart]="chartRef" 
          [options]="showcaseLegendOptions()"
          (itemClick)="onLegendItemClick($event)"
          (itemMouseEnter)="onLegendItemMouseEnter($event)"
          (itemMouseLeave)="onLegendItemMouseLeave($event)"
        />
      </div>
      <div class="legend-info">
        <p>Click on legend items to interact with the chart</p>
      </div>
    </div>
  `,
  imports: [AXChartLegendComponent, AXDonutChartComponent],
  styles: [`
    .showcase-container {
      padding: 2rem;
      background: var(--ax-sys-color-lightest-surface);
      border-radius: 8px;
    }
    .chart-legend-demo {
      display: flex;
      gap: 2rem;
      align-items: center;
      justify-content: center;
    }
    .legend-info {
      margin-top: 1rem;
      text-align: center;
      color: var(--ax-sys-color-on-lightest-surface);
    }
  `]
})
export class ChartLegendShowcaseComponent {
  showcaseData = signal<AXDonutChartData[]>([
    { id: 'sales', label: 'Sales', value: 40, color: '#3498db' },
    { id: 'marketing', label: 'Marketing', value: 25, color: '#e74c3c' },
    { id: 'development', label: 'Development', value: 20, color: '#2ecc71' },
    { id: 'support', label: 'Support', value: 15, color: '#f39c12' }
  ]);

  showcaseChartOptions = signal<AXDonutChartOption>({
    width: 300,
    height: 300,
    showTooltip: true,
    donutWidth: 30,
    cornerRadius: 6,
    animationDuration: 1000,
    animationEasing: 'ease-in-out'
  });

  showcaseLegendOptions = signal<AXChartLegendOptions>({
    mode: 'vertical',
    showValues: true,
    showPercentage: true,
    interactive: true
  });

  onLegendItemClick(item: AXChartLegendItem): void {
    console.log('Legend item clicked:', item);
  }

  onLegendItemMouseEnter(item: AXChartLegendItem): void {
    console.log('Legend item mouse enter:', item);
  }

  onLegendItemMouseLeave(item: AXChartLegendItem): void {
    console.log('Legend item mouse leave:', item);
  }
}

